mapper.select:
SELECT p.id, p.browse_num, p.collect_num, p.comment_num, p.forward_num, DATE_FORMAT( p.create_time, '%Y-%m-%d %H:%i:%s' ) AS create_time, p.is_home_recommend, p.like_num, f.name, f.need_platform_review, p.title, p.status, p.user_id, p.content, p.images, p.video_id, p.type, p.forward_num, f.name as user_name, f.head_img as headimgurl, p.pro_ids, p.forum_id, v.cover_img, p.cover_img as p_cover_img, p.text FROM lkt_bbs_post p LEFT JOIN lkt_bbs_forum f ON f.id = p.forum_id LEFT JOIN lkt_bbs_video v ON v.file_id = p.video_id
p.create_time desc, p.id = #{sort_post_id} desc,p.create_time desc,
limit #{pageNo},#{pageSize}

SELECT id FROM lkt_bbs_post WHERE forum_id IN

    #{forum_id}

and recycle = 0 and status = 2

SELECT f.id FROM lkt_bbs_forum f WHERE f.recycle = 0
AND f.store_id = #{store_id}
AND f.user_id IN ( SELECT DISTINCT a.be_user_id FROM lkt_bbs_post_action a WHERE a.user_id = #{user_id} AND a.action_type = 4 AND a.recycle = 0 AND a.be_user_id IS NOT NULL AND a.be_user_id != '' )
